<script setup>
import { ref, useTemplateRef } from 'vue'

const props = defineProps({
  placeholder: { type: String, default: '说点什么…' },
  disabled: { type: Boolean, default: false },
})
const emit = defineEmits(['send'])

const text = ref('')
const inputRef = useTemplateRef('inputRef')

function send() {
  const value = text.value.trim()
  if (!value || props.disabled) return
  emit('send', value)
  text.value = ''
  inputRef.value?.focus()
}

function onEnter(e) {
  if (e.shiftKey) return  // Shift+Enter 换行
  e.preventDefault()
  send()
}
</script>

<template>
  <div
    class="flex items-end gap-2 px-3 py-3 border-t border-akong-border bg-white"
    data-testid="chat-input"
  >
    <textarea
      ref="inputRef"
      v-model="text"
      :placeholder="placeholder"
      :disabled="disabled"
      rows="1"
      class="flex-1 px-3 py-2.5 rounded-2xl bg-akong-paper border border-akong-border text-sm leading-snug max-h-32 resize-none focus:outline-none focus:border-akong-accent transition-colors"
      data-testid="input-textarea"
      @keydown.enter="onEnter"
    />
    <button
      :disabled="disabled || !text.trim()"
      class="shrink-0 w-10 h-10 rounded-full bg-akong-accent text-white text-sm flex items-center justify-center disabled:opacity-30 disabled:cursor-not-allowed transition-opacity"
      data-testid="send-btn"
      @click="send"
    >
      <slot name="send-icon">→</slot>
    </button>
  </div>
</template>
